// OpenCL kernel code for kmeans clustering adaptation
// This kernel replaces the OpenMP parallel region in kmeans_clustering function

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void kmeans_assign_clusters(
    __global const float* features,       // Flattened feature array: npoints * nfeatures
    __global const float* clusters,       // Flattened clusters array: nclusters * nfeatures
    __global int* membership,             // Membership array for each point
    __global float* partial_new_centers,  // Partial sums per thread: nthreads * nclusters * nfeatures
    __global int* partial_new_centers_len,// Partial counts per thread: nthreads * nclusters
    const int nfeatures,
    const int npoints,
    const int nclusters,
    const int nthreads)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int group_size = get_local_size(0);
    int group_id = get_group_id(0);

    // Each work-item processes one data point
    if (gid < npoints) {
        // Find nearest cluster
        float min_dist = FLT_MAX;
        int index = 0;
        for (int c = 0; c < nclusters; c++) {
            float dist = 0.0f;
            for (int f = 0; f < nfeatures; f++) {
                float diff = features[gid * nfeatures + f] - clusters[c * nfeatures + f];
                dist += diff * diff;
            }
            if (dist < min_dist) {
                min_dist = dist;
                index = c;
            }
        }

        int old_membership = membership[gid];
        membership[gid] = index;

        // Note: delta reduction not implemented here; host code can compute delta if needed

        // Accumulate partial sum for new centers
        int tid = group_id * group_size + lid;  // global thread id
        // Since OpenCL threads are typically many, we assume nthreads passed corresponds to total global size
        // Store partial sums in partial_new_centers and counts in partial_new_centers_len
        // Use atomic operations to avoid race conditions

        // Increment count for this cluster
        atomic_inc(&partial_new_centers_len[tid * nclusters + index]);

        // Sum features for this cluster
        for (int f = 0; f < nfeatures; f++) {
            // Atomic add for float is not available in OpenCL 2.0 on all devices,
            // so we emulate with atomic_add on int if possible or use local memory reduction.
            // Here we assume device supports atomic_add on floats (cl_khr_fp64 or cl_khr_fp16)
            // Otherwise, this must be done on host or with other methods.

            // Note: atomic_add on float requires OpenCL 2.0 or extension
            atomic_add(&partial_new_centers[(tid * nclusters + index) * nfeatures + f], features[gid * nfeatures + f]);
        }
    }
}
